create extension if not exists pgcrypto;
create table public.households(id uuid primary key default gen_random_uuid(), slug text unique not null, name text not null, created_at timestamptz not null default now());
create table public.profiles(id uuid primary key default gen_random_uuid(), household_id uuid not null references public.households on delete cascade, display_name text not null check(display_name in ('Nahuel','ML','lili')), unique(household_id,display_name));
create table public.access_grants(auth_user_id uuid primary key references auth.users on delete cascade, profile_id uuid not null references public.profiles on delete cascade, expires_at timestamptz not null, created_at timestamptz not null default now());
create view public.active_access with (security_invoker=true) as select p.id,p.display_name,p.household_id,g.expires_at from public.access_grants g join public.profiles p on p.id=g.profile_id where g.auth_user_id=auth.uid() and g.expires_at>now();
create table public.locations(id uuid primary key default gen_random_uuid(),household_id uuid not null references public.households on delete cascade,parent_id uuid references public.locations on delete set null,name text not null,type text not null,notes text,owner text not null check(owner in ('Nahuel','ML','lili','Compartido')),created_by_profile uuid references public.profiles,created_at timestamptz not null default now(),updated_at timestamptz not null default now(),deleted_at timestamptz);
create table public.boxes(id uuid primary key default gen_random_uuid(),household_id uuid not null references public.households on delete cascade,parent_box_id uuid references public.boxes on delete set null,location_id uuid references public.locations on delete set null,name text not null,description text,category text,owner text not null check(owner in ('Nahuel','ML','lili','Compartido')),exterior_photo_path text,created_by_profile uuid references public.profiles,created_at timestamptz not null default now(),updated_at timestamptz not null default now(),deleted_at timestamptz);
create table public.items(id uuid primary key default gen_random_uuid(),household_id uuid not null references public.households on delete cascade,box_id uuid references public.boxes on delete set null,location_id uuid references public.locations on delete set null,name text not null,description text,category text,owner text not null check(owner in ('Nahuel','ML','lili','Compartido')),photo_path text,created_by_profile uuid references public.profiles,created_at timestamptz not null default now(),updated_at timestamptz not null default now(),deleted_at timestamptz,check(not(box_id is not null and location_id is not null)));
create index on public.locations(household_id);create index on public.boxes(household_id);create index on public.items(household_id);create index on public.boxes using gin(to_tsvector('spanish',coalesce(name,'')||' '||coalesce(description,'')||' '||coalesce(category,'')));create index on public.items using gin(to_tsvector('spanish',coalesce(name,'')||' '||coalesce(description,'')||' '||coalesce(category,'')));
create or replace function public.has_household_access(hid uuid) returns boolean language sql stable security definer set search_path=public as $$select exists(select 1 from access_grants g join profiles p on p.id=g.profile_id where g.auth_user_id=auth.uid() and g.expires_at>now() and p.household_id=hid)$$;
revoke all on function public.has_household_access(uuid) from public;grant execute on function public.has_household_access(uuid) to authenticated;
alter table public.households enable row level security;alter table public.profiles enable row level security;alter table public.access_grants enable row level security;alter table public.locations enable row level security;alter table public.boxes enable row level security;alter table public.items enable row level security;
create policy household_read on public.households for select to authenticated using(public.has_household_access(id));
create policy profile_read on public.profiles for select to authenticated using(public.has_household_access(household_id));
create policy own_grant_read on public.access_grants for select to authenticated using(auth_user_id=auth.uid());create policy own_grant_delete on public.access_grants for delete to authenticated using(auth_user_id=auth.uid());
create policy location_all on public.locations for all to authenticated using(public.has_household_access(household_id)) with check(public.has_household_access(household_id));
create policy box_all on public.boxes for all to authenticated using(public.has_household_access(household_id)) with check(public.has_household_access(household_id));
create policy item_all on public.items for all to authenticated using(public.has_household_access(household_id)) with check(public.has_household_access(household_id));
insert into storage.buckets(id,name,public,file_size_limit,allowed_mime_types) values('household-images','household-images',false,5242880,array['image/webp','image/jpeg','image/png']) on conflict(id) do update set public=false;
create policy images_select on storage.objects for select to authenticated using(bucket_id='household-images' and public.has_household_access((storage.foldername(name))[2]::uuid));
create policy images_insert on storage.objects for insert to authenticated with check(bucket_id='household-images' and public.has_household_access((storage.foldername(name))[2]::uuid));
create policy images_update on storage.objects for update to authenticated using(bucket_id='household-images' and public.has_household_access((storage.foldername(name))[2]::uuid)) with check(bucket_id='household-images' and public.has_household_access((storage.foldername(name))[2]::uuid));
create policy images_delete on storage.objects for delete to authenticated using(bucket_id='household-images' and public.has_household_access((storage.foldername(name))[2]::uuid));
create or replace function public.purge_soft_deleted() returns void language plpgsql security definer set search_path=public as $$begin delete from items where deleted_at<now()-interval '30 days';delete from boxes where deleted_at<now()-interval '30 days';delete from locations where deleted_at<now()-interval '30 days';end$$;
